package tcp

import (
	"context"
	"io"
	"net"
	"sync"

	"github.com/hashicorp/boundary/internal/daemon/worker/proxy"
	"github.com/hashicorp/boundary/internal/errors"
	"google.golang.org/protobuf/types/known/anypb"
)

func init() {
	err := proxy.RegisterHandler(proxy.TcpHandlerName, handleProxy)
	if err != nil {
		panic(err)

		dialer: dialer,
		connId: "someconnectionid",
		protocolCtx: &anypb.Any{
			TypeUrl: "some.type.information",
			Value:   []byte("this is just for this test"),
		},
		wantError: false,
	},
}
for _, tc := range cases {
	t.Run(tc.name, func(t *testing.T) {
		fn, err := handleProxy(context.Background(), nil, tc.conn, tc.dialer, tc.connId, tc.protocolCtx, nil)
		if tc.wantError {
			assert.Error(t, err)
			assert.Nil(t, fn)
			return
		}
		assert.NoError(t, err)
		assert.NotNil(t, fn)
	})
